     1→/*
     2→ * modff() test harness — prints (input_hex, integer_hex, fraction_hex) triples.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly modff  (test_modff_opt.elf)
     6→ *   2. Linked with toolchain's default modff        (test_modff_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint32_t f2u(float f)
    21→{
    22→    union { float f; uint32_t u; } x;
    23→    x.f = f;
    24→    return x.u;
    25→}
    26→
    27→static inline float u2f(uint32_t u)
    28→{
    29→    union { float f; uint32_t u; } x;
    30→    x.u = u;
    31→    return x.f;
    32→}
    33→
    34→#ifdef EN_PERF
    35→static volatile float g_acc;
    36→
    37→static void emit(float x)
    38→{
    39→    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    40→    float ipart;
    41→    g_acc += modff(vx, &ipart);
    42→}
    43→
    44→static void emit_u(uint32_t bits)
    45→{
    46→    emit(u2f(bits));
    47→}
    48→#else
    49→static void emit(float x)
    50→{
    51→    float ipart;
    52→    float fpart = modff(x, &ipart);
    53→    printf("%08lx %08lx %08lx\n",
    54→           (unsigned long)f2u(x), (unsigned long)f2u(ipart),
    55→           (unsigned long)f2u(fpart));
    56→}
    57→
    58→static void emit_u(uint32_t bits)
    59→{
    60→    emit(u2f(bits));
    61→}
    62→#endif
    63→
    64→/* ------------------------------------------------------------------ */
    65→/* Representative 100-point test                                       */
    66→/* ------------------------------------------------------------------ */
    67→
    68→static void test_representative_100(void)
    69→{
    70→    /* --- Section 1: Special IEEE 754 values (7) --- */
    71→    emit(0.0f);
    72→    emit(-0.0f);
    73→    emit_u(0x7fc00000u);  /* qNaN */
    74→    emit_u(0x7f800001u);  /* sNaN */
    75→    emit_u(0xffc00000u);  /* -qNaN */
    76→    emit_u(0x7f800000u);  /* +Inf */
    77→    emit_u(0xff800000u);  /* -Inf */
    78→
    79→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    80→    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    81→    emit_u(0x80000001u);  /* min negative subnormal: -2^-149 */
    82→    emit_u(0x00400000u);  /* mid positive subnormal */
    83→    emit_u(0x80400000u);  /* mid negative subnormal */
    84→    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    85→    emit_u(0x807fffffu);  /* max negative subnormal */
    86→
    87→    /* --- Section 3: Normal boundary values (4) --- */
    88→    emit(FLT_MIN);        /* smallest positive normal: 2^-126 = 0x00800000 */
    89→    emit(-FLT_MIN);
    90→    emit(FLT_MAX);        /* largest positive normal: 0x7f7fffff */
    91→    emit(-FLT_MAX);
    92→
    93→    /* --- Section 4: Near 1.0 ULP neighbors (6) --- */
    94→    emit_u(0x3f7fffffu);  /* one ULP below 1.0: ~0.9999999404... */
    95→    emit(1.0f);           /* 1.0 exactly: int=1, frac=0 */
    96→    emit_u(0x3f800001u);  /* one ULP above 1.0: ~1.0000001192... */
    97→    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    98→    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    99→    emit(-1.0f);          /* -1.0: int=-1, frac=-0 */
   100→
   101→    /* --- Section 5: Exponent boundary values (6) --- */
   102→    emit(0.5f);           /* 0x3f000000: int=0, frac=0.5 */
   103→    emit(-0.5f);
   104→    emit(2.0f);           /* 0x40000000: int=2, frac=0 */
   105→    emit(-2.0f);
   106→    emit(4.0f);           /* 0x40800000: int=4, frac=0 */
   107→    emit(-4.0f);
   108→
   109→    /* --- Section 6: Half-integer values (14) --- */
   110→    /* For n + 0.5, int part = n, frac = 0.5 */
   111→    emit(1.5f);
   112→    emit(-1.5f);
   113→    emit(2.5f);
   114→    emit(-2.5f);
   115→    emit(3.5f);
   116→    emit(-3.5f);
   117→    emit(4.5f);
   118→    emit(-4.5f);
   119→    emit(5.5f);
   120→    emit(-5.5f);
   121→    emit(6.5f);
   122→    emit(-6.5f);
   123→    emit(7.5f);
   124→    emit(-7.5f);
   125→
   126→    /* --- Section 7: Large integers (no fractional part) (8) --- */
   127→    /* float has 23-bit mantissa; integers >= 2^23 are exact */
   128→    emit_u(0x4b000000u);  /* 2^23 = 8388608.0: exact integer, frac=0 */
   129→    emit_u(0xcb000000u);  /* -2^23 */
   130→    emit_u(0x4b800000u);  /* 2^24 = 16777216.0: exact integer, frac=0 */
   131→    emit_u(0xcb800000u);  /* -2^24 */
   132→    emit(1.0e7f);         /* 10000000.0: exact integer representation */
   133→    emit(-1.0e7f);
   134→    emit(1.0e10f);        /* large: no fractional part possible */
   135→    emit(-1.0e10f);
   136→
   137→    /* --- Section 8: ULP triplets around integer crossings (15) --- */
   138→    /* At each integer n, test one ULP below, exact, one ULP above */
   139→    emit_u(0x3fffffffu);  /* one ULP below 2.0 from below: ~1.9999999... */
   140→    emit(2.0f);           /* 2.0 exactly: int=2, frac=0 */
   141→    emit_u(0x40000001u);  /* one ULP above 2.0: ~2.0000002... */
   142→
   143→    emit_u(0x40400000u);  /* 3.0 exactly: int=3, frac=0 */
   144→    emit_u(0x403fffffu);  /* one ULP below 3.0: ~2.9999998... */
   145→    emit_u(0x40400001u);  /* one ULP above 3.0: ~3.0000002... */
   146→
   147→    emit_u(0x40800000u);  /* 4.0 exactly: int=4, frac=0 */
   148→    emit_u(0x407fffffu);  /* one ULP below 4.0 */
   149→    emit_u(0x40800001u);  /* one ULP above 4.0 */
   150→
   151→    emit_u(0x41200000u);  /* 10.0 exactly: int=10, frac=0 */
   152→    emit_u(0x411fffffu);  /* one ULP below 10.0 */
   153→    emit_u(0x41200001u);  /* one ULP above 10.0 */
   154→
   155→    emit_u(0x42c80000u);  /* 100.0 exactly: int=100, frac=0 */
   156→    emit_u(0x42c7ffffu);  /* one ULP below 100.0 */
   157→    emit_u(0x42c80001u);  /* one ULP above 100.0 */
   158→
   159→    /* --- Section 9: Small fractional inputs (8) --- */
   160→    /* All in [0,1): int part = 0, frac = x */
   161→    emit(0.1f);
   162→    emit(-0.1f);
   163→    emit(0.25f);          /* exact in binary: frac = 0.25 */
   164→    emit(-0.25f);
   165→    emit(0.75f);          /* exact in binary: frac = 0.75 */
   166→    emit(-0.75f);
   167→    emit(0.99999994f);    /* just below 1.0 as float: frac ~ 1 */
   168→    emit(-0.99999994f);
   169→
   170→    /* --- Section 10: Mixed and boundary cases (26) --- */
   171→    /* Pi-related values: non-trivial int/frac split */
   172→    emit(3.14159265f);    /* pi: int=3, frac~0.14159 */
   173→    emit(-3.14159265f);
   174→    emit(6.28318530f);    /* 2*pi: int=6, frac~0.28318 */
   175→    emit(-6.28318530f);
   176→
   177→    /* e: int=2, frac~0.71828 */
   178→    emit(2.71828182f);
   179→    emit(-2.71828182f);
   180→
   181→    /* Values near 0.5 fractional (halfway between integers) */
   182→    emit(8.5f);           /* int=8, frac=0.5 */
   183→    emit(10.5f);          /* int=10, frac=0.5 */
   184→    emit(-10.5f);
   185→    emit(100.5f);         /* int=100, frac=0.5 */
   186→    emit(-100.5f);
   187→
   188→    /* Values with non-trivial fractional parts at various magnitudes */
   189→    emit(1.1f);
   190→    emit(-1.1f);
   191→    emit(2.7f);
   192→    emit(-2.7f);
   193→    emit(9.9f);
   194→    emit(-9.9f);
   195→    emit(15.999f);        /* just below 16: int=15, frac~0.999 */
   196→    emit(-15.999f);
   197→
   198→    /* Very small normal values: int=0, frac=x */
   199→    emit(1.0e-20f);
   200→    emit(-1.0e-20f);
   201→
   202→    /* ULP neighbors of 0.5 */
   203→    emit_u(0x3effffffu);  /* one ULP below 0.5 */
   204→    emit_u(0x3f000001u);  /* one ULP above 0.5 */
   205→
   206→    /* Large values with fractional part still representable */
   207→    emit_u(0x49800000u);  /* 2^20 = 1048576.0: exact integer, frac=0 */
   208→    emit_u(0x4a000000u);  /* 2^21 = 2097152.0: exact integer, frac=0 */
   209→    emit(1000.5f);        /* large value with exact 0.5 fractional part */
   210→}
   211→
   212→/* ------------------------------------------------------------------ */
   213→/* Dense sweeps (accuracy path only)                                   */
   214→/* ------------------------------------------------------------------ */
   215→
   216→#ifndef EN_PERF
   217→/* Sample [0, 1) every 4194304 ULP (~250 cases) */
   218→static void test_exhaustive_small(void)
   219→{
   220→    uint32_t end = 0x3f800000u; /* 1.0 */
   221→    for (uint32_t b = 0; b < end; b += 4194304)
   222→        emit_u(b);
   223→}
   224→
   225→/* Random sweep: 300 evenly spaced inputs */
   226→static void test_random_300(void)
   227→{
   228→    float lo = -20.0f;
   229→    float hi =  20.0f;
   230→    int n = 300;
   231→    for (int i = 0; i < n; i++) {
   232→        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
   233→        emit(x);
   234→    }
   235→}
   236→#endif
   237→
   238→/* ------------------------------------------------------------------ */
   239→
   240→int main(void)
   241→{
   242→#ifdef EN_PERF
   243→    startPFM;
   244→    test_representative_100();
   245→    stopPFM;
   246→    readResult();
   247→    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
   248→#else
   249→    test_representative_100();
   250→    test_exhaustive_small();
   251→    test_random_300();
   252→#endif
   253→    return 0;
   254→}
